body {
  display: grid;
  place-items: center;
  min-height: 100vh;
  background: #eef2f7;
}

.cta {
  border: 0;
  padding: 12px 22px;
  background: #2a9d8f;
  color: white;
  border-radius: 10px;
  font-weight: 700;
  cursor: pointer;
  transition: transform 0.2s ease, background 0.2s ease;
}

/* Define los estados hover, focus y active */
